import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://learn.netdata.cloud/docs/netdata-cloud/authentication-%26-authorization/api-tokens";
const PLACEHOLDER_VALUE =
  "eyJhbGciOiJub25lIiwidHlwIjoiSldUIn0.eyJpc3MiOiJuZXRkYXRhIiwic3ViIjoiY29mZmVlLXNhZmUtbG9jYWwiLCJhdWQiOiJ2bTAtY29ubmVjdG9yIn0.";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Netdata Cloud API token docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:netdata",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const netdataFirewall = {",
    '  name: "netdata",',
    '  description: "Netdata Cloud API",',
    "  placeholders: {",
    `    NETDATA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://app.netdata.cloud",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.NETDATA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Netdata firewall config...");
  const ts = generateTypeScript();
  writeOutput("netdata", ts, import.meta.dirname);
}
